 10→const BASE = import.meta.env.VITE_API_BASE ?? "";
 11→
 12→async function request<T>(path: string, init?: RequestInit): Promise<T> {
 13→  const res = await fetch(`${BASE}${path}`, {
 14→    headers: { "Content-Type": "application/json" },
 15→    ...init,
 16→  });
 17→  if (!res.ok) {
 18→    throw new Error(`API error ${res.status}: ${await res.text()}`);
 19→  }
 20→  return res.json() as Promise<T>;
 21→}
 22→
